solution.code:
def bitwise_add(a, b):
    if b == 0: return a
    res = a ^ b
    carry = (a & b) << 1
    return bitwise_add(res, carry)

if __name__ == "__main__":
    print(f"2 + 2 = {bitwise_add(2, 2)}")
